namespace BgControls.Windows.Controls.DragDrop;internal class HideDuringLayoutChangeHelper{    private static Dictionary<FrameworkElement, HideDuringLayoutChangeHelper> hookedElements = new Dictionary<FrameworkElement, HideDuringLayoutChangeHelper>();    private Visibility lastVisibility;    private IEnumerable<INotifyLayoutChange> Parents { get; set; }    private FrameworkElement Element { get; set; }    internal static void OnHideDuringLayoutChangeChanged(DependencyObject d, DependencyPropertyChangedEventArgs e)    {        FrameworkElement frameworkElement = d as FrameworkElement;        bool flag = (bool)e.NewValue;        if (frameworkElement != null)        {            if (flag)            {                Attach(frameworkElement);            }            else            {                Detach(frameworkElement);            }        }    }    private static void Detach(FrameworkElement element)    {        HideDuringLayoutChangeHelper hideDuringLayoutChangeHelper = hookedElements[element];        element.Loaded -= hideDuringLayoutChangeHelper.OnElementLoaded;        hideDuringLayoutChangeHelper.DetachEvents();        hookedElements.Remove(element);    }    private static void Attach(FrameworkElement element)    {        HideDuringLayoutChangeHelper hideDuringLayoutChangeHelper = new HideDuringLayoutChangeHelper();        hideDuringLayoutChangeHelper.Parents = INotifyLayoutChangeParents(element);        hideDuringLayoutChangeHelper.Element = element;        HideDuringLayoutChangeHelper hideDuringLayoutChangeHelper2 = hideDuringLayoutChangeHelper;        hookedElements.Add(element, hideDuringLayoutChangeHelper2);        hideDuringLayoutChangeHelper2.AttachEvents();        element.Loaded += hideDuringLayoutChangeHelper2.OnElementLoaded;    }    private static IEnumerable<INotifyLayoutChange> INotifyLayoutChangeParents(UIElement element)    {        if (element == null)        {            yield break;        }        for (DependencyObject parent = VisualTreeHelper.GetParent(element); parent != null; parent = VisualTreeHelper.GetParent(parent))        {            if (parent is INotifyLayoutChange)            {                yield return (INotifyLayoutChange)parent;            }        }    }    private void AttachEvents()    {        foreach (INotifyLayoutChange parent in Parents)        {            parent.LayoutChangeStarted += LayoutChangeStarted;            parent.LayoutChangeEnded += LayoutChangeEnded;        }    }    private void DetachEvents()    {        foreach (INotifyLayoutChange parent in Parents)        {            parent.LayoutChangeStarted -= LayoutChangeStarted;            parent.LayoutChangeEnded -= LayoutChangeEnded;        }    }    private void OnElementLoaded(object sender, EventArgs args)    {        DetachEvents();        Parents = INotifyLayoutChangeParents(Element);        AttachEvents();        if (Parents.Any((INotifyLayoutChange p) => p.IsLayoutChanging))        {            lastVisibility = Element.Visibility;            Element.Visibility = Visibility.Collapsed;        }    }    private void LayoutChangeStarted(object sender, EventArgs args)    {        lastVisibility = Element.Visibility;        Element.Visibility = Visibility.Collapsed;    }    private void LayoutChangeEnded(object sender, EventArgs args)    {        Element.Visibility = lastVisibility;    }}